data class User(val name: String?, val active: Boolean?)

fun findActiveNames(users: List<User?>): List<String> {
    var result = mutableListOf<String>()
    for (u in users) {
        if (u != null) {
            if (u.active == true) {
                result.add(u.name!!)
            }
        }
    }
    return result
}
